INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'How much space is needed?', 'Each A-Frame Tent set up requires approximately a 3ft by 6ft space. If you are unsure if you have enough space you can provide us with measurements and pictures of the set up area and we can help determine the best layout.', 0 FROM packages WHERE slug = 'tent-sleepover';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What if I don''t have my final guest count yet?', 'We recommend booking for the maximum number of guests that you may have as we can not guarantee that additional items will be available. You have up until 2 weeks before your event (when your final payment is due) to make any changes.', 1 FROM packages WHERE slug = 'tent-sleepover';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What if I need to cancel?', 'Cancellation 2 Weeks +
If you have to cancel or reschedule your event your 25% deposit may be used as a credit towards a new event within 13 months of your original event date. In addition, you are entitled to a refund of any amount paid above the 25% deposit.
Cancellations within 2 Weeks
If you are canceling your event within 2 weeks, your full payment may be used as a credit towards a new event within 13 months of your original event date.
Cancellations within 24 hours
If you are canceling your event within 24 hours of your scheduled delivery time, your full payment, minus a rescheduling fee, may be used as a credit towards a new event within 13 months of your original event date.', 2 FROM packages WHERE slug = 'tent-sleepover';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'When do you set up and pick up?', 'You will receive a confirmation email one week prior to your event with a 2 hour delivery and pick up window. Deliveries for indoor sleepover will take place between the hours of 9:00am-4:00pm. Pick ups for all sleepover packages will begin at 10:00am the next day.', 3 FROM packages WHERE slug = 'tent-sleepover';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'How is everything cleaned?', 'All hard surfaces are thoroughly disinfected with CDC approved cleaning agents after each use and all linens are professionally laundered.', 4 FROM packages WHERE slug = 'tent-sleepover';
