INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'When do you set up and pick up?', 'You will receive a confirmation email one week prior to your event with a 2 hour delivery and pick up window. Deliveries for outdoor events will begin at 8:00am (9:00am for indoor events) and go throughout the day. We will schedule delivery based on the event start time provided at the time of booking. The rental period for a picnic is 6 hours, unless paired with one of our Sleepover or Lounges Package. Pick ups for Picnic Packages will vary. Please contact us with any questions. There are many factors that go into our delivery and pick up schedules including your guest counts, package type, location, weather and our other scheduled events. We may be able to accommodate requests for specific delivery/pick up times if our schedule allows. However, it is not guaranteed. If you need a guaranteed specific delivery and/or pick up time additional fees may apply. Any request must be sent via email no later than 2 weeks before your event.', 3 FROM packages WHERE slug = 'celebrations-picnic-adult';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'When will I get my damage deposit back?', 'Your damage deposit will be refunded the Monday after your event as long as all inventory is returned free from any damage.
Damage includes but is not limited to any of the following: stains, broken inventory, missing pieces, and water damage (including damage from tents being left open and items being left out in the rain and/or overnight).
Please note damage deposits are only charged for OUTDOOR events.', 4 FROM packages WHERE slug = 'celebrations-picnic-adult';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Can I choose my theme/color scheme?', 'Yes! We have several themes/color schemes for you to choose from. We can also put together a custom theme for your event. Additional fees may apply for custom themes. Price varies based on level of customization and size of event. Please contact us for a quote.', 5 FROM packages WHERE slug = 'celebrations-picnic-adult';
