INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What happens if it rains?', 'In the event of inclement weather we are happy to reschedule for another date pending availability. You must notify us a minimum of 24 hours before your scheduled delivery window in order to reschedule.', 0 FROM packages WHERE slug = 'megamovie-night';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'When do you set up and pick up?', 'You will receive a confirmation email one week prior to your event with delivery and pick up information. Deliveries for outdoor events will begin at 8:00am and go throughout the day. We will schedule delivery based on your event start time provided at the time of booking. Pick up will take place the same day after your event ends. Picks ups after 11:00pm will be charged an After Hours Pick Up Fee. There are many factors that go into our delivery and pick up schedules including your guest counts, package type, location, weather and our other scheduled events. We may be able to accommodate requests for specific delivery/pick up times if our schedule allows. However, it is not guaranteed. If you need a guaranteed specific delivery and/or pick up time additional fees may apply. Any request must be sent via email no later than 2 weeks before your event.', 1 FROM packages WHERE slug = 'megamovie-night';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Do you need access to power?', 'Yes, access to power is needed to run the projector. We will provide ample extension cords.', 2 FROM packages WHERE slug = 'megamovie-night';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Do you provide the movie?', 'While we do not provide the movie we will provide either a DVD/Blue Ray Player or FireStick. You are responsible for providing a DVD/Blue Ray or for streaming a movie through your own account (Netflix, Hulu, etc.). Please note that if you plan to stream a movie there must be a strong internet signal (wifi or data) available at the movie site.', 3 FROM packages WHERE slug = 'megamovie-night';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Do you stay for the event?', 'We do not stay for the event. We set up everything you need, leave you to enjoy your event and return the next day (or later that day upon request).', 4 FROM packages WHERE slug = 'megamovie-night';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Do you stay for the event?', 'We do not stay for the event. We set up everything you need, leave you to enjoy your event and return the next day (or later that day upon request).', 0 FROM packages WHERE slug = 'pamper-party';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What do guests get to keep?', 'Each guest gets to keep their Spa Slippers, Spa Headband, Applicator Brush, and Facial Products (face wipes, face mask, lotion) and Mani/Pedi Products (bath bomb, toe separators, nail file, nail brush). Robes are for event use only, but personalized satin robes can be added as an option for guests to keep.', 1 FROM packages WHERE slug = 'pamper-party';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What if I need to cancel?', 'Cancellation 2 Weeks +
If you have to cancel or reschedule your event your 25% deposit may be used as a credit towards a new event within 13 months of your original event date. In addition, you are entitled to a refund of any amount paid above the 25% deposit.
Cancellations within 2 Weeks
If you are canceling your event within 2 weeks, your full payment may be used as a credit towards a new event within 13 months of your original event date.
Cancellations within 24 hours
If you are canceling your event within 24 hours of your scheduled delivery time, your full payment, minus a rescheduling fee, may be used as a credit towards a new event within 13 months of your original event date.', 2 FROM packages WHERE slug = 'pamper-party';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'How is everything cleaned?', 'All hard surfaces are thoroughly disinfected with CDC approved cleaning agents after each use and all linens are professionally laundered.', 3 FROM packages WHERE slug = 'pamper-party';
